// Build Workflow Execution Rows with Workflow Names
// Schema-safe for public.workflow_executions
// Filters executions that started within the past 7 hours.
// Reads time_saved_minutes from n8n workflow settings.

const workflowsNodeName = 'n8n | List Workflows';
const executionsNodeName = 'n8n | List Executions';

const LOOKBACK_HOURS = 7;

const cutoffDate = new Date(Date.now() - LOOKBACK_HOURS * 60 * 60 * 1000);

const workflowItems = $(workflowsNodeName).all();
const executionItems = $(executionsNodeName).all();

function flattenData(items) {
  return items.flatMap(item => {
    if (Array.isArray(item.json.data)) return item.json.data;
    return [item.json];
  });
}

function toIso(value) {
  if (!value) return null;
  const date = new Date(value);
  return isNaN(date.getTime()) ? null : date.toISOString();
}

function getDurationSeconds(startedAt, stoppedAt) {
  if (!startedAt || !stoppedAt) return null;
  const start = new Date(startedAt);
  const stop = new Date(stoppedAt);
  if (isNaN(start.getTime()) || isNaN(stop.getTime())) return null;
  return Number(((stop.getTime() - start.getTime()) / 1000).toFixed(2));
}

function deriveStatus(execution) {
  if (execution.status) return execution.status;
  if (execution.stoppedAt && execution.finished === true) return 'success';
  if (execution.stoppedAt && execution.finished === false) return 'error';
  if (!execution.stoppedAt && execution.startedAt) return 'running';
  if (execution.waitTill) return 'waiting';
  return null;
}

const workflows = flattenData(workflowItems);
const executions = flattenData(executionItems);

// Build workflow_id → workflow_name + time_saved_minutes lookup
const workflowLookup = {};

for (const workflow of workflows) {
  const workflowId =
    workflow.id ||
    workflow.workflow_id ||
    workflow.workflowId ||
    null;

  if (!workflowId) continue;

  workflowLookup[workflowId] = {
    workflow_name:
      workflow.name ||
      workflow.workflow_name ||
      null,
    time_saved_minutes: workflow.settings?.timeSavedPerExecution ?? 0,
  };
}

const filteredExecutions = executions.filter(execution => {
  if (!execution.id) return false;

  const startedAtRaw =
    execution.startedAt ||
    execution.started_at ||
    execution.createdAt ||
    execution.created_at ||
    null;

  if (!startedAtRaw) return false;

  const startedAtDate = new Date(startedAtRaw);
  if (isNaN(startedAtDate.getTime())) return false;

  return startedAtDate >= cutoffDate;
});

return filteredExecutions.map(execution => {
  const workflowId =
    execution.workflowId ||
    execution.workflow_id ||
    execution.workflow?.id ||
    null;

  const workflowMetadata = workflowLookup[workflowId] || {};

  const startedAt = toIso(
    execution.startedAt ||
    execution.started_at ||
    execution.createdAt ||
    execution.created_at
  );

  const stoppedAt = toIso(
    execution.stoppedAt ||
    execution.stopped_at
  );

  return {
    json: {
      execution_id: String(execution.id),

      workflow_id: workflowId,

      workflow_name:
        execution.workflowName ||
        execution.workflow_name ||
        execution.workflow?.name ||
        workflowMetadata.workflow_name ||
        null,

      status: deriveStatus(execution),

      mode:
        execution.mode ||
        null,

      started_at: startedAt,

      stopped_at: stoppedAt,

      wait_till:
        toIso(execution.waitTill || execution.wait_till),

      duration_seconds:
        getDurationSeconds(startedAt, stoppedAt),

      retry_of:
        execution.retryOf ||
        execution.retry_of ||
        null,

      retry_success_id:
        execution.retrySuccessId ||
        execution.retry_success_id ||
        null,

      error_message:
        execution.error?.message ||
        execution.errorMessage ||
        execution.error_message ||
        null,

      // Time-saved reporting fields
      time_saved_minutes: workflowMetadata.time_saved_minutes ?? 0,
      time_saved_source: 'workflow_settings',
      time_saved_reason: 'Estimated time saved from n8n workflow settings',

      synced_at: new Date().toISOString(),
    }
  };
});
